        (EventLocations.LOGIC_TH_COULD_FREE_SLOPE_CARPENTER, lambda bundle: setting(RSK_GERUDO_FORTRESS) == RO_GF_CARPENTERS_FREE or setting(RSK_GERUDO_FORTRESS) == RO_GF_CARPENTERS_FAST),
